<?php
declare(strict_types=1);

function quotation_bulk_import_dir(): string { $d=__DIR__.'/../data/quotation_bulk_imports'; if(!is_dir($d)) @mkdir($d,0775,true); return $d; }
function quotation_bulk_audit_path(): string { return quotation_bulk_import_dir().'/batches.json'; }
function quotation_bulk_safe_csv_cell($v): string { $s=(string)$v; return preg_match('/^[=+\-@]/',$s) ? "'".$s : $s; }
function quotation_bulk_required_headers(): array { return ['import_key','customer_name','customer_mobile','party_type','template_set','system_type','selected_model_number','main_solar_kwp','non_dcr_kwp','quotation_date','valid_until','scenario_price_self_funded','scenario_price_loan_upto_2_lacs','scenario_price_loan_above_2_lacs']; }
function quotation_bulk_optional_headers(): array { return ['billing_address','site_address','district','city','state','pin','meter_number','meter_serial_number','consumer_account_no','application_id','application_submitted_date','sanction_load_kwp','installed_pv_module_capacity_kwp','circle_name','division_name','sub_division_name','tax_profile','place_of_supply_state','primary_finance_scenario','monthly_bill_rs','unit_rate_rs_per_kwh','annual_generation_per_kw','subsidy_expected_rs','transportation_rs','discount_rs','discount_note','special_requests_text','hybrid_inverter_kva','hybrid_phase','hybrid_battery_count']; }
function quotation_bulk_all_headers(): array { return array_merge(quotation_bulk_required_headers(), quotation_bulk_optional_headers()); }
function quotation_bulk_send_csv(string $filename, array $headers, array $rows): void { header('Content-Type: text/csv; charset=UTF-8'); header('Content-Disposition: attachment; filename="'.$filename.'"'); echo "\xEF\xBB\xBF"; $out=fopen('php://output','w'); fputcsv($out,array_map('quotation_bulk_safe_csv_cell',$headers)); foreach($rows as $row){ $line=[]; foreach($headers as $h){ $line[]=quotation_bulk_safe_csv_cell(is_array($row)?($row[$h]??''):''); } fputcsv($out,$line); } fclose($out); exit; }
function quotation_bulk_send_template(): void { quotation_bulk_send_csv('quotation-import-template.csv', quotation_bulk_all_headers(), [[ 'party_type'=>'lead','system_type'=>'ongrid','primary_finance_scenario'=>'self_funded','state'=>'Jharkhand','place_of_supply_state'=>'Jharkhand' ]]); }
function quotation_bulk_send_reference_data(array $templates, array $quoteDefaults): void { $headers=['type','id_or_key','name','details']; $rows=[]; foreach($templates as $t){$rows[]=['type'=>'template','id_or_key'=>(string)($t['id']??''),'name'=>(string)($t['name']??''),'details'=>'segment '.(string)($t['segment']??'')];} foreach(['on_grid','hybrid'] as $type){foreach((array)($quoteDefaults['rate_chart'][$type]??[]) as $r){if(is_array($r))$rows[]=['type'=>'rate_chart_model','id_or_key'=>(string)($r['model_number']??''),'name'=>$type,'details'=>json_encode($r,JSON_UNESCAPED_SLASHES)];}} foreach(['ongrid','hybrid'] as $st){$rows[]=['type'=>'system_type','id_or_key'=>$st,'name'=>$st,'details'=>''];} foreach(documents_inventory_kits(false) as $k){$rows[]=['type'=>'matching_kit','id_or_key'=>(string)($k['id']??''),'name'=>(string)($k['name']??''),'details'=>(string)($k['description']??'')];} foreach(documents_inventory_tax_profiles(false) as $p){$rows[]=['type'=>'tax_profile','id_or_key'=>(string)($p['id']??''),'name'=>(string)($p['name']??''),'details'=>json_encode($p,JSON_UNESCAPED_SLASHES)];} foreach(['self_funded','loan_upto_2_lacs','loan_above_2_lacs','loan_upto_2_lacs_subsidy_to_loan','loan_above_2_lacs_subsidy_to_loan'] as $s){$rows[]=['type'=>'finance_scenario','id_or_key'=>$s,'name'=>$s,'details'=>''];} quotation_bulk_send_csv('quotation-import-reference-data.csv',$headers,$rows); }
function quotation_bulk_read_csv_upload(?array $upload): array { if(!$upload||($upload['error']??UPLOAD_ERR_NO_FILE)!==UPLOAD_ERR_OK)return ['ok'=>false,'error'=>'CSV upload failed.']; $name=(string)($upload['name']??''); if(strtolower(pathinfo($name,PATHINFO_EXTENSION))!=='csv')return ['ok'=>false,'error'=>'Only .csv files are allowed.']; if((int)($upload['size']??0)>1024*1024)return ['ok'=>false,'error'=>'CSV file must be 1 MB or smaller.']; $fh=fopen((string)$upload['tmp_name'],'r'); if(!$fh)return ['ok'=>false,'error'=>'Unable to read CSV.']; $headers=fgetcsv($fh); if(!$headers){fclose($fh);return ['ok'=>false,'error'=>'CSV is empty.'];} if(isset($headers[0]))$headers[0]=preg_replace('/^\xEF\xBB\xBF/','',(string)$headers[0]); $headers=array_map(fn($h)=>trim((string)$h),$headers); $missing=array_diff(quotation_bulk_required_headers(),$headers); if($missing){fclose($fh);return ['ok'=>false,'error'=>'Missing columns: '.implode(', ',$missing)];} $rows=[]; $rowNum=1; while(($data=fgetcsv($fh))!==false){$rowNum++; if(count(array_filter($data,fn($v)=>trim((string)$v)!==''))===0)continue; if(count($rows)>=200){fclose($fh);return ['ok'=>false,'error'=>'CSV row limit is 200.'];} $row=[]; foreach($headers as $i=>$h)$row[$h]=(string)($data[$i]??''); $rows[]=['row_number'=>$rowNum,'data'=>$row]; } fclose($fh); @unlink((string)$upload['tmp_name']); return ['ok'=>true,'filename'=>$name,'rows'=>$rows]; }
function documents_build_quote_draft_from_input(array $input, array $context=[]): array { $dry=!empty($context['dry_run']); $templates=(array)($context['templates']??[]); $defaults=(array)($context['quote_defaults']??load_quote_defaults()); $messages=[]; $templateKey=safe_text((string)($input['template_set']??'')); $tpl=null; foreach($templates as $t){ if((string)($t['id']??'')===$templateKey || strcasecmp((string)($t['name']??''),$templateKey)===0){$tpl=$t;break;} } if(!$tpl)$messages[]='Template set is not active or not found.'; $mobile=documents_normalize_mobile((string)($input['customer_mobile']??'')); if($mobile==='')$messages[]='Customer mobile is required.'; $name=safe_text((string)($input['customer_name']??'')); if($name==='')$messages[]='Customer name is required.'; $system=documents_quote_normalize_system_type((string)($input['system_type']??'ongrid')); $model=safe_text((string)($input['selected_model_number']??'')); $rateType=$system==='hybrid'?'hybrid':'on_grid'; $rate=[]; foreach((array)($defaults['rate_chart'][$rateType]??[]) as $r){ if(is_array($r)&&safe_text((string)($r['model_number']??''))===$model){$rate=$r;break;} } if(!$rate)$messages[]='Selected model number was not found in the active rate chart for '.$system.'.'; $dcr=(float)($input['main_solar_kwp']??0); $non=(float)($input['non_dcr_kwp']??0); $total=$dcr+$non; if($dcr<=0||$total<=0)$messages[]='DCR/main capacity must be greater than 0.'; $taxId=safe_text((string)($input['tax_profile']??'')); if($taxId!==''){ $ok=false; foreach(documents_inventory_tax_profiles(false) as $p){ if((string)($p['id']??'')===$taxId||strcasecmp((string)($p['name']??''),$taxId)===0){$taxId=(string)($p['id']??'');$ok=true;break;} } if(!$ok)$messages[]='Tax profile is not active or not found.'; }
 $priceSelf=(float)($input['scenario_price_self_funded']!==''?$input['scenario_price_self_funded']:($rate['self_funded_price']??0)); $priceUp=(float)($input['scenario_price_loan_upto_2_lacs']!==''?$input['scenario_price_loan_upto_2_lacs']:($rate['loan_upto_2_lacs_price']??0)); $priceAbove=(float)($input['scenario_price_loan_above_2_lacs']!==''?$input['scenario_price_loan_above_2_lacs']:($rate['loan_above_2_lacs_price']??0)); $primary=safe_text((string)($input['primary_finance_scenario']??'self_funded')); if(!in_array($primary,['self_funded','loan_upto_2_lacs','loan_above_2_lacs','loan_upto_2_lacs_subsidy_to_loan','loan_above_2_lacs_subsidy_to_loan'],true)){$messages[]='Primary finance scenario is not allowed.';$primary='self_funded';} if($priceSelf<=0)$messages[]='Self-funded scenario price must be greater than 0.'; if($tpl&&$messages===[]){ $quote=documents_quote_defaults(); $quote['id']=$dry?'preview_'.substr(hash('sha1',json_encode($input)),0,12):'qtn_'.date('YmdHis').'_'.bin2hex(random_bytes(3)); if(!$dry){$num=documents_generate_quote_number((string)($tpl['segment']??'RES')); if(!($num['ok']??false))return ['ok'=>false,'messages'=>[(string)($num['error']??'Unable to generate quotation number.')]]; $quote['quote_no']=(string)$num['quote_no'];} else {$quote['quote_no']='PREVIEW';} $quote['created_at']=date('c'); $quote['updated_at']=date('c'); $quote['status']='Draft'; $quote['segment']=(string)($tpl['segment']??'RES'); $quote['template_set_id']=(string)($tpl['id']??''); $quote['party_type']=in_array((string)($input['party_type']??'lead'),['customer','lead'],true)?(string)$input['party_type']:'lead'; $quote['customer_name']=$name; $quote['customer_mobile']=$mobile; foreach(['billing_address','site_address','district','city','state','pin','meter_number','meter_serial_number','consumer_account_no','application_id','application_submitted_date','sanction_load_kwp','installed_pv_module_capacity_kwp','circle_name','division_name','sub_division_name','quotation_date','valid_until','special_requests_text'] as $f){$quote[$f]=safe_text((string)($input[$f]??''));} $quote['system_type']=$system; $quote['main_solar_kwp']=(string)$dcr; $quote['complimentary_non_dcr_kwp']=(string)$non; $quote['capacity_kwp']=(string)$total; $quote['system_capacity_kwp']=$total; $quote['tax_profile_id']=$taxId; $quote['place_of_supply_state']=safe_text((string)($input['place_of_supply_state']??'Jharkhand')); $quote['primary_finance_scenario']=$primary; $quote['scenario_prices']=['self_funded'=>['price'=>$priceSelf],'loan_upto_2_lacs'=>['price'=>$priceUp],'loan_above_2_lacs'=>['price'=>$priceAbove]]; $quote['rate_chart_snapshot']=array_merge($rate,['system_type'=>$system,'model_number'=>$model,'dcr_size_kwp'=>$dcr,'non_dcr_size_kwp'=>$non,'total_system_size_kwp'=>$total,'solar_size_kwp'=>$total,'self_funded_price'=>$priceSelf,'loan_upto_2_lacs_price'=>$priceUp,'loan_above_2_lacs_price'=>$priceAbove,'hybrid_inverter_kva'=>(float)($input['hybrid_inverter_kva']??($rate['inverter_kva']??0)),'hybrid_phase'=>safe_text((string)($input['hybrid_phase']??($rate['phase']??''))),'hybrid_battery_count'=>(int)($input['hybrid_battery_count']??($rate['battery_count']??0)),'captured_at'=>date('c')]); $quote=documents_quote_reconcile_system_configuration($quote); if(safe_text((string)($quote['system_reconcile_error']??''))!=='')return ['ok'=>false,'messages'=>[(string)$quote['system_reconcile_error']]]; if(function_exists('solar_finance_sync_hybrid_summary_into_quote_items'))$quote=solar_finance_sync_hybrid_summary_into_quote_items($quote); $sub=(float)($input['subsidy_expected_rs']??0); $transport=(float)($input['transportation_rs']??0); $primaryPrice=$primary==='loan_upto_2_lacs'?$priceUp:($primary==='loan_above_2_lacs'?$priceAbove:$priceSelf); $quote['calc']=documents_calc_quote_pricing_with_tax_profile($quote,$transport,$sub,$primaryPrice,$defaults); $quote['input_total_gst_inclusive']=$primaryPrice; $quote['finance_inputs']=['subsidy_expected_rs'=>(string)$sub,'transportation_rs'=>(string)$transport,'discount_rs'=>(string)(float)($input['discount_rs']??0),'discount_note'=>safe_text((string)($input['discount_note']??''))]; $quote['customer_snapshot']=array_merge(documents_customer_snapshot_defaults(),['mobile'=>$mobile,'name'=>$name,'address'=>$quote['site_address'],'city'=>$quote['city'],'district'=>$quote['district'],'pin_code'=>$quote['pin'],'state'=>$quote['state']]); $quote['bulk_import_meta']=(array)($context['import_meta']??[]); if(!$dry){$u=current_user();$quote['created_by_type']='admin';$quote['created_by_id']=(string)($u['id']??'');$quote['created_by_name']=(string)($u['full_name']??'Admin'); $saved=documents_save_quote($quote); if(!($saved['ok']??false))return ['ok'=>false,'messages'=>['Failed to save quotation.']];} return ['ok'=>true,'quote'=>$quote,'messages'=>$messages]; } return ['ok'=>false,'messages'=>$messages]; }
function quotation_bulk_imported_index(): array { $idx=[]; foreach(json_load(quotation_bulk_audit_path(),[])?:[] as $b){foreach((array)($b['results']??[]) as $r){if(!empty($r['created_quote_id'])){if(($r['import_key']??'')!=='')$idx['key'][$r['import_key']]=true; if(($r['row_hash']??'')!=='')$idx['hash'][$r['row_hash']]=true;}}} return $idx; }
function quotation_bulk_validate_rows(array $rows,array $templates,array $defaults,string $filename): array { $idx=quotation_bulk_imported_index(); $seen=[]; $out=[];$counts=['total'=>0,'valid'=>0,'invalid'=>0,'warning'=>0,'duplicate'=>0]; foreach($rows as $rr){$counts['total']++;$in=$rr['data'];$hash=hash('sha256',json_encode($in));$res=documents_build_quote_draft_from_input($in,['dry_run'=>true,'templates'=>$templates,'quote_defaults'=>$defaults]);$msgs=$res['messages']??[];$warn=[];$key=safe_text((string)($in['import_key']??'')); if($key==='' )$msgs[]='Import key is required.'; if(isset($seen[$key])||isset($seen[$hash])||isset($idx['key'][$key])||isset($idx['hash'][$hash])){$warn[]='Duplicate import key or row hash detected.';$counts['duplicate']++;} $seen[$key]=true;$seen[$hash]=true; $q=$res['quote']??[]; $status=($res['ok']??false)?($warn?'Warning':'Valid'):'Error'; if($status==='Valid')$counts['valid']++; elseif($status==='Warning'){$counts['valid']++;$counts['warning']++;} else $counts['invalid']++; $out[]=['row_number'=>$rr['row_number'],'import_key'=>$key,'customer'=>(string)($in['customer_name']??''),'system_model'=>(string)($in['system_type']??'').'/'.(string)($in['selected_model_number']??''),'dcr'=>(float)($in['main_solar_kwp']??0),'non_dcr'=>(float)($in['non_dcr_kwp']??0),'total'=>(float)($in['main_solar_kwp']??0)+(float)($in['non_dcr_kwp']??0),'template'=>(string)($in['template_set']??''),'amount'=>(float)($q['input_total_gst_inclusive']??0),'item_count'=>count((array)($q['quote_items']??[])),'status'=>$status,'messages'=>array_merge($msgs,$warn),'input'=>$in,'row_hash'=>$hash,'filename'=>$filename]; } return ['rows'=>$out,'counts'=>$counts]; }
function quotation_bulk_append_batch(array $batch): void { $all=json_load(quotation_bulk_audit_path(),[]); if(!is_array($all))$all=[]; array_unshift($all,$batch); json_save(quotation_bulk_audit_path(),array_slice($all,0,50)); }
function quotation_bulk_recent_batches(): array { $all=json_load(quotation_bulk_audit_path(),[]); return is_array($all)?array_slice($all,0,10):[]; }
